pub async fn jwt_middleware(req: HttpRequest, next: Next<Body>) -> Result<HttpResponse, actix_web::Error> {
    let token = req.headers().get("Authorization")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.strip_prefix("Bearer "))
        .ok_or_else(|| actix_web::error::ErrorUnauthorized("missing token"))?;
    let config = req.app_data::<web::Data<JwtConfig>>().unwrap();
    let decoded = jsonwebtoken::decode::<Claims>(token, &config.decoding, &Validation::default())
        .map_err(|_| actix_web::error::ErrorUnauthorized("invalid token"))?;
    req.extensions_mut().insert(decoded.claims);
    next.call(req).await
}
